import java.io.IOException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import javax.servlet.ServletException;
import javax.servlet.http.HttpServlet;

public class SecureServlet extends HttpServlet {

    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Properly sanitize and escape user input before outputting it to the response
        String sanitizedInput = sanitizeInput(userInput);

        response.getWriter().println("<p>User Input: " + sanitizedInput + "</p>");
    }

    private String sanitizeInput(String input) {
        // Implement proper sanitization logic here based on your application's requirements
        // For example, you can use OWASP ESAPI library or HTML escaping functions

        // Here is an example of using OWASP ESAPI for HTML escaping:
        return org.owasp.esapi.Encoder.getInstance().encodeForHTML(input);
    }
}

